impl Solution { pub fn double_it(mut head: Option<Box<ListNode>>) -> Option<Box<ListNode>> { if head.as_ref().unwrap().val >= 5 { head = Some(Box::new(ListNode { val: 0, next: head })); } let mut black_curr = &mut head; while let Some(node) = black_curr { node.val = (node.val * 2) % 10; if let Some(next_node) = &node.next { if next_node.val >= 5 { node.val += 1; } } black_curr = &mut node.next; } head } }